{
  "summary": "This paper introduces AmbiBench, a benchmark designed to study task ambiguity in language models through six binary classification tasks with ambiguous instructions. It empirically evaluates human and model performance, showing that RLHF-trained models excel at disambiguation, and proposes finetuning on ambiguous examples as an effective alternative to RLHF. The work highlights the challenges of task ambiguity and suggests directions for improving model robustness.",
  "strengths": [
    {
      "point": "Novel benchmark for task ambiguity",
      "evidence": "AmbiBench provides a controlled setting with six ambiguously-specified binary classification tasks to systematically study task ambiguity."
    },
    {
      "point": "Comprehensive empirical evaluation",
      "evidence": "The paper compares humans, various LMs including RLHF and non-RLHF models, across different instruction informativeness and example counts."
    },
    {
      "point": "Insightful finetuning approach",
      "evidence": "Finetuning on ambiguous in-context examples improves standard LM performance, even surpassing RLHF models on early examples."
    },
    {
      "point": "Clear motivation and problem formulation",
      "evidence": "The paper distinguishes task ambiguity from input ambiguity and motivates its importance for real-world LM deployment."
    }
  ],
  "weaknesses": [
    {
      "point": "Limited scope with only binary classification tasks",
      "evidence": "AmbiBench tasks involve only two possible linguistic features per sentence, which may oversimplify real-world task ambiguity."
    },
    {
      "point": "Insufficient comparison to prior work on ambiguity",
      "evidence": "The paper lacks a thorough literature review on ambiguity in NLP tasks such as intent detection or semantic parsing."
    },
    {
      "point": "Lack of detailed human baseline information",
      "evidence": "Details on human participants’ expertise, fatigue mitigation, and learning effects are missing, raising questions about baseline reliability."
    },
    {
      "point": "Unsubstantiated claims about RLHF superiority",
      "evidence": "No empirical ablations or controlled experiments are provided to confirm that RLHF models’ advantage stems from exposure to ambiguous instructions."
    },
    {
      "point": "Missing finetuning and dataset details",
      "evidence": "Key hyperparameters, dataset size, selection criteria, and dataset format/licensing are not specified, hindering reproducibility."
    },
    {
      "point": "Limited evaluation metrics and analysis",
      "evidence": "Evaluation focuses mainly on accuracy and invalid label rates without deeper error analysis, confidence calibration, or statistical testing."
    },
    {
      "point": "No comparison to alternative disambiguation methods",
      "evidence": "The paper does not benchmark finetuning against prompt engineering, active learning, or uncertainty estimation techniques."
    },
    {
      "point": "Narrow operational definition of ambiguity",
      "evidence": "Defining ambiguity as two plausible tasks per example may confuse readers expecting broader ambiguity notions."
    },
    {
      "point": "Unclear generalizability beyond binary tasks",
      "evidence": "The paper does not explore or discuss whether findings extend to tasks with more than two ambiguous interpretations or multimodal inputs."
    }
  ],
  "questions": [
    {
      "question": "How does the finetuning approach compare to other disambiguation strategies like prompt engineering or active learning?",
      "motivation": "Understanding relative effectiveness is important for practical deployment and further research."
    },
    {
      "question": "Can the methods and findings generalize to more complex tasks with multiple ambiguous interpretations or multimodal inputs?",
      "motivation": "Real-world applications often involve richer ambiguity, so scalability and adaptability are critical."
    },
    {
      "question": "What specific aspects of RLHF training contribute to improved ambiguity resolution, and can these be isolated empirically?",
      "motivation": "Clarifying this would guide future model training and benchmarking."
    },
    {
      "question": "How were human participant factors such as expertise and fatigue controlled or accounted for?",
      "motivation": "Ensuring reliable human baselines is essential for fair human-model comparisons."
    }
  ],
  "scores": {
    "correctness": 3,
    "novelty": 3,
    "recommendation": "borderline",
    "confidence": 3
  }
}
